import React, { useState } from "react";
import { useTranslation } from "react-i18next";
import { theme, Table, Button, Input, Space, Tag, Typography, Card, Avatar, Tooltip, Modal, Form, Select, App, Flex } from "antd";
import { 
  UserOutlined, 
  SearchOutlined, 
  PlusOutlined, 
  EditOutlined,
  DeleteOutlined,
  LockOutlined,
  MailOutlined,
  TeamOutlined
} from "@ant-design/icons";

const { useToken } = theme;
const { Title, Text } = Typography;
const { Option } = Select;

interface UserData {
  key: string;
  userId: string;
  userName: string;
  email: string;
  role: "admin" | "manager" | "worker";
  status: "active" | "inactive";
  asgnNm: string;
  lastLogin: string;
}

const mockUsers: UserData[] = [
  { key: "1", userId: "admin", userName: "관리자", email: "admin@m-safety.com", role: "admin", status: "active", asgnNm: "HQ (IT Team)", lastLogin: "2026-04-07 10:20" },
  { key: "2", userId: "worker_01", userName: "홍길동", email: "gd.hong@partner.com", role: "worker", status: "active", asgnNm: "Partner A", lastLogin: "2026-04-07 09:15" },
  { key: "3", userId: "worker_02", userName: "이순신", email: "ss.lee@partner.com", role: "worker", status: "inactive", asgnNm: "Partner A", lastLogin: "2026-04-05 14:30" },
  { key: "4", userId: "manager_km", userName: "김매니저", email: "km.kim@m-safety.com", role: "manager", status: "active", asgnNm: "HQ (Ops Team)", lastLogin: "2026-04-07 08:45" },
];

export default function UserManagement() {
  const { token } = useToken();
  const { t } = useTranslation(["user", "common", "org"]);
  const { message } = App.useApp();
  const [users, setUsers] = useState<UserData[]>(mockUsers);
  const [searchText, setSearchText] = useState("");
  const [isModalVisible, setIsModalVisible] = useState(false);
  const [editingUser, setEditingUser] = useState<UserData | null>(null);
  const [form] = Form.useForm();

  const handleAddOrEdit = () => {
    form.validateFields().then((values) => {
      if (editingUser) {
        setUsers(users.map(u => u.key === editingUser.key ? { ...u, ...values } : u));
        message.success(t("save", { ns: "common" }));
      } else {
        const newUser: UserData = {
          key: (users.length + 1).toString(),
          userId: values.userId,
          userName: values.userName,
          email: values.email,
          role: values.role,
          status: "active",
          asgnNm: values.asgn === "HQ_IT" ? "HQ (IT)" : "Partner A",
          lastLogin: "-"
        };
        setUsers([...users, newUser]);
        message.success(t("create", { ns: "common" }));
      }
      setIsModalVisible(false);
      setEditingUser(null);
      form.resetFields();
    });
  };

  const handleDelete = (key: string) => {
    setUsers(users.filter(u => u.key !== key));
    message.warning(t("msg.deleted"));
  };

  const handleResetPassword = (userId: string) => {
    message.info(t("msg.pwdReset", { userId }));
  };

  const handleToggleStatus = (key: string) => {
    setUsers(users.map(u => u.key === key ? { ...u, status: u.status === "active" ? "inactive" : "active" } : u));
    message.info(t("msg.statusChanged"));
  };

  const showEditModal = (user: UserData) => {
    setEditingUser(user);
    form.setFieldsValue({
      userId: user.userId,
      userName: user.userName,
      email: user.email,
      role: user.role,
      asgn: user.asgnNm.includes("HQ") ? "HQ_IT" : "P_A"
    });
    setIsModalVisible(true);
  };

  const columns = [
    {
      title: t("userId"),
      dataIndex: "userId",
      key: "userId",
      render: (text: string) => <Text strong>{text}</Text>,
    },
    {
      title: t("userName"),
      dataIndex: "userName",
      key: "userName",
      render: (text: string) => (
        <Space>
          <Avatar icon={<UserOutlined />} size="small" />
          {text}
        </Space>
      ),
    },
    {
      title: t("email"),
      dataIndex: "email",
      key: "email",
    },
    {
      title: t("org"),
      dataIndex: "asgnNm",
      key: "asgnNm",
      render: (text: string) => <Tag icon={<TeamOutlined />}>{text}</Tag>,
    },
    {
      title: t("role"),
      dataIndex: "role",
      key: "role",
      render: (role: string) => {
        const colors = { admin: "magenta", manager: "blue", worker: "cyan" };
        return <Tag color={colors[role as keyof typeof colors]}>{role.toUpperCase()}</Tag>;
      },
    },
    {
      title: t("status"),
      dataIndex: "status",
      key: "status",
      render: (status: string, record: UserData) => (
        <Tooltip title={t("status")}>
          <Tag 
            color={status === "active" ? "green" : "red"} 
            style={{ cursor: "pointer" }}
            onClick={() => handleToggleStatus(record.key)}
          >
            {status.toUpperCase()}
          </Tag>
        </Tooltip>
      ),
    },
    {
      title: t("lastLogin"),
      dataIndex: "lastLogin",
      key: "lastLogin",
    },
    {
      title: t("select", { ns: "common" }),
      key: "action",
      render: (_: any, record: UserData) => (
        <Space size="small">
          <Tooltip title={t("edit", { ns: "common" })}><Button type="text" icon={<EditOutlined />} onClick={() => showEditModal(record)} /></Tooltip>
          <Tooltip title={t("resetPassword")}><Button type="text" icon={<LockOutlined />} onClick={() => handleResetPassword(record.userId)} /></Tooltip>
          <Tooltip title={t("delete", { ns: "common" })}><Button type="text" danger icon={<DeleteOutlined />} onClick={() => handleDelete(record.key)} /></Tooltip>
        </Space>
      ),
    },
  ];

  return (
    <div style={{ padding: "0 24px 24px 24px" }}>
      <div style={{ marginBottom: 16, display: "flex", justifyContent: "space-between", alignItems: "flex-end" }}>
        <Flex vertical gap={2}>
          <Title level={3} style={{ margin: 0 }}>{t("title")}</Title>
          <Text type="secondary">{t("subtitle")}</Text>
        </Flex>
        
        <Space>
          <Input 
            placeholder={t("searchPlaceholder", { ns: "common" })} 
            prefix={<SearchOutlined />} 
            style={{ width: 250 }} 
            onChange={(e) => setSearchText(e.target.value)}
          />
          <Button type="primary" icon={<PlusOutlined />} onClick={() => setIsModalVisible(true)}>{t("registerBtn")}</Button>
        </Space>
      </div>

      <Card variant="borderless" styles={{ body: { padding: 0 } }} style={{ borderRadius: 12, overflow: "hidden", boxShadow: token.boxShadowSecondary }}>
        <Table 
          dataSource={users.filter(u => u.userName.includes(searchText) || u.userId.includes(searchText))} 
          columns={columns} 
          pagination={{ pageSize: 10 }}
          locale={{ emptyText: t("noObjects", { ns: "common" }) }}
        />
      </Card>

      <Modal
        title={editingUser ? t("edit", { ns: "common" }) : t("registerBtn")}
        open={isModalVisible}
        onOk={handleAddOrEdit}
        onCancel={() => {
          setIsModalVisible(false);
          setEditingUser(null);
          form.resetFields();
        }}
        okText={editingUser ? t("save", { ns: "common" }) : t("create", { ns: "common" })}
        cancelText={t("cancel", { ns: "common" })}
        width={480}
        destroyOnHidden
      >
        <Form form={form} layout="vertical" style={{ marginTop: 20 }}>
          <Form.Item name="userId" label={t("userId")} rules={[{ required: true, message: t("userId") }]}>
            <Input prefix={<UserOutlined />} placeholder={t("userId")} disabled={!!editingUser} />
          </Form.Item>
          <Form.Item name="userName" label={t("userName")} rules={[{ required: true, message: t("userName") }]}>
            <Input placeholder={t("userName")} />
          </Form.Item>
          <Form.Item name="email" label={t("email")} rules={[{ required: true, type: "email", message: t("email") }]}>
            <Input prefix={<MailOutlined />} placeholder="example@m-safety.com" />
          </Form.Item>
          <Form.Item name="role" label={t("role")} initialValue="worker">
            <Select>
              <Option value="admin">{t("roles.manager", { ns: "org" })} (Admin)</Option>
              <Option value="manager">Manager</Option>
              <Option value="worker">{t("roles.worker", { ns: "org" })}</Option>
            </Select>
          </Form.Item>
          <Form.Item name="asgn" label={t("org")} rules={[{ required: true }]}>
            <Select placeholder={t("select", { ns: "common" })}>
              <Option value="HQ_IT">HQ (IT Team)</Option>
              <Option value="HQ_OP">HQ (Ops Team)</Option>
              <Option value="P_A">Partner A</Option>
              <Option value="P_B">Partner B</Option>
            </Select>
          </Form.Item>
        </Form>
      </Modal>
    </div>
  );
}
